def login_redirect(user_authenticated, intended_url, default_url='/home'):
    if user_authenticated:
        # Ensure the intended URL is safe
        if intended_url and intended_url.startswith('/'):
            return intended_url
        else:
            return default_url
    else:
        return default_url

